import{_ as t,o as d,c as r,W as e}from"./chunks/framework.71c88ce2.js";const P=JSON.parse('{"title":"HTTP","description":"","frontmatter":{},"headers":[],"relativePath":"net/http.md","filePath":"net/http.md","lastUpdated":1689679322000}'),a={name:"net/http.md"},o=e('<h1 id="http" tabindex="-1">HTTP <a class="header-anchor" href="#http" aria-label="Permalink to &quot;HTTP&quot;">​</a></h1><h2 id="http-报文" tabindex="-1">HTTP 报文 <a class="header-anchor" href="#http-报文" aria-label="Permalink to &quot;HTTP 报文&quot;">​</a></h2><h2 id="http-常见状态码" tabindex="-1">HTTP 常见状态码 <a class="header-anchor" href="#http-常见状态码" aria-label="Permalink to &quot;HTTP 常见状态码&quot;">​</a></h2><p>状态码的职责是当客户端向服务器端发送请求时，描述返回的请求结果。借助状态码，用户可以知道服务器端是正常处理了请求，还是出现了错误。</p><table><thead><tr><th>状态码</th><th>英文名称</th><th>中文描述</th></tr></thead><tbody><tr><td>200</td><td>ok</td><td>客户端的请求已被服务器正常处理</td></tr><tr><td>204</td><td>No Content</td><td>客户端的请求已被服务器正常处理，但没有返回内容</td></tr><tr><td>206</td><td>Partial</td><td>客户端进行了范围请求，服务器成功执行了这部分(视频流)</td></tr><tr><td>301</td><td>Moved</td><td>永久性重定向</td></tr><tr><td>302</td><td>Found</td><td>临时性重定向</td></tr><tr><td>303</td><td>See Other</td><td>临时性重定向，表示重定向要以 get 方式请求</td></tr><tr><td>304</td><td>Not</td><td>客户端发送附带条件的请求时，服务器端允许请求</td></tr><tr><td>307</td><td>Temporary</td><td>临时性重定向</td></tr><tr><td>400</td><td>Bad</td><td>服务器端无法理解客户端发送的请求</td></tr><tr><td>401</td><td>Unauthorized</td><td>客户端请求需要用户认证</td></tr><tr><td>403</td><td>Forbidden</td><td>服务器端拒绝该次请求</td></tr><tr><td>404</td><td>Not Found</td><td>客户端请求的资源不存在</td></tr><tr><td>500</td><td>Internal</td><td>服务器端在执行请求时发生了错误</td></tr><tr><td>503</td><td>Service</td><td>服务器暂时性的无法处理客户端的请求</td></tr></tbody></table>',5),h=[o];function n(i,s,_,c,l,p){return d(),r("div",null,h)}const u=t(a,[["render",n]]);export{P as __pageData,u as default};
